{"path": "/tmp/sv-103e72cc479141729751be7f5a1868a6/Services/MockChatService.cs", "file_text": "namespace sv_103e72cc479141729751be7f5a1868a6.Services;

public class MockChatService : IChatService
{
    private readonly List<Channel> _channels =
    [
        new(1, "general", "General discussion for the team", 3),
        new(2, "engineering", "Engineering updates and discussions", 0),
        new(3, "design", "Design reviews and feedback", 1),
        new(4, "random", "Off-topic conversations", 5),
        new(5, "announcements", "Important team announcements", 0)
    ];

    private readonly List<Message> _messages = [];
    private int _nextId = 1;

    public MockChatService()
    {
        var now = DateTime.UtcNow;

        // General channel — main conversation
        int welcomeId = AddMsg(1, "Alice", "Hey everyone! Welcome to the new chat app 🎉",
            now.AddHours(-5), null, [new("🎉", ["Bob", "Carol"])]);
        AddMsg(1, "Bob", "Thanks Alice! This looks great.",
            now.AddHours(-4.5), null, []);
        // Thread replies to welcome message
        AddMsg(1, "Carol", "Love the new design!",
            now.AddHours(-4), welcomeId, [new("👍", ["Alice"])]);
        AddMsg(1, "Dave", "Agreed, much better than before.",
            now.AddHours(-3.5), welcomeId, []);
        AddMsg(1, "Alice", "Has anyone reviewed the Q3 roadmap?",
            now.AddHours(-3), null, [new("👀", ["Bob"])]);
        AddMsg(1, "Bob", "I'll take a look this afternoon",
            now.AddMinutes(-45), null, []);
        AddMsg(1, "Carol", "Meeting in 10 minutes, don't forget!",
            now.AddMinutes(-10), null, [new("👍", ["Alice", "Bob", "Dave"])]);
        AddMsg(1, "Dave", "On my way!",
            now.AddMinutes(-8), null, []);

        // Older messages for pagination testing
        for (int i = 0; i < 25; i++)
        {
            AddMsg(1, i % 2 == 0 ? "Alice" : "Bob",
                $"Earlier message #{i + 1} in general",
                now.AddDays(-2).AddHours(i), null, []);
        }

        // Engineering channel
        int prId = AddMsg(2, "Dave", "PR #142 is ready for review",
            now.AddHours(-2), null, []);
        AddMsg(2, "Alice", "I'll review it after lunch",
            now.AddHours(-1.5), null, []);
        AddMsg(2, "Bob", "Found a small issue in the error handling",
            now.AddMinutes(-30), prId, []);
        AddMsg(2, "Dave", "Good catch, fixing now",
            now.AddMinutes(-20), prId, [new("👍", ["Bob"])]);
        AddMsg(2, "Carol", "CI pipeline is green again 🟢",
            now.AddMinutes(-5), null, [new("🎉", ["Alice", "Bob", "Dave"])]);

        // Design channel
        AddMsg(3, "Carol", "New mockups are in Figma, please review",
            now.AddHours(-6), null, [new("👀", ["Alice"])]);
        AddMsg(3, "Alice", "The color palette looks fantastic!",
            now.AddHours(-5), null, [new("❤️", ["Carol"])]);
        AddMsg(3, "Bob", "Can we adjust the spacing on the sidebar?",
            now.AddHours(-3), null, []);

        // Random channel
        AddMsg(4, "Bob", "Anyone up for lunch at the new place?",
            now.AddHours(-1), null, [new("👍", ["Carol", "Dave"])]);
        AddMsg(4, "Carol", "Count me in!",
            now.AddMinutes(-50), null, []);
        AddMsg(4, "Dave", "I'll pass today, maybe next time",
            now.AddMinutes(-40), null, []);

        // Announcements channel
        AddMsg(5, "Alice", "Team outing next Friday! Details in email.",
            now.AddDays(-1), null, [new("🎉", ["Bob", "Carol", "Dave"])]);
        AddMsg(5, "Alice", "New PTO policy effective next month",
            now.AddHours(-8), null, [new("👍", ["Bob"])]);
    }

    private int AddMsg(int channelId, string author, string content,
        DateTime sentAt, int? replyToId, List<Reaction> reactions)
    {
        var id = _nextId++;
        _messages.Add(new Message(id, channelId, author, content, sentAt, replyToId, reactions));
        return id;
    }

    public Task<List<Channel>> GetChannelsAsync()
        => Task.FromResult(_channels.ToList());

    public Task<List<Message>> GetMessagesAsync(int channelId, int skip, int take)
    {
        var result = _messages
            .Where(m => m.ChannelId == channelId && m.ReplyToId == null)
            .OrderByDescending(m => m.SentAt)
            .Skip(skip)
            .Take(take)
            .OrderBy(m => m.SentAt)
            .ToList();
        return Task.FromResult(result);
    }

    public Task<Message> SendMessageAsync(int channelId, string content, int? replyToId)
    {
        var msg = new Message(_nextId++, channelId, "You", content, DateTime.UtcNow, replyToId, []);
        _messages.Add(msg);
        return Task.FromResult(msg);
    }

    public Task<List<Message>> GetThreadAsync(int rootMessageId)
    {
        var root = _messages.FirstOrDefault(m => m.Id == rootMessageId);
        if (root is null)
            return Task.FromResult(new List<Message>());

        var thread = new List<Message> { root };
        thread.AddRange(_messages
            .Where(m => m.ReplyToId == rootMessageId)
            .OrderBy(m => m.SentAt));
        return Task.FromResult(thread);
    }

    public Task AddReactionAsync(int messageId, string emoji)
        => Task.CompletedTask;

    public Task MarkChannelReadAsync(int channelId)
    {
        var idx = _channels.FindIndex(c => c.Id == channelId);
        if (idx >= 0)
            _channels[idx] = _channels[idx] with { UnreadCount = 0 };
        return Task.CompletedTask;
    }
}
"}

