@using sv_103e72cc479141729751be7f5a1868a6.Services

<div class="channel-item @(IsActive ? "active" : "")" @onclick="HandleClick">
    <div class="channel-top-row">
        <span class="channel-name"># @Channel.Name</span>
        @if (Channel.UnreadCount > 0)
        {
            <span class="unread-badge">@Channel.UnreadCount</span>
        }
    </div>
    <div class="channel-description">@Channel.Description</div>
</div>

@code {
    [Parameter, EditorRequired] public Channel Channel { get; set; } = default!;
    [Parameter] public bool IsActive { get; set; }
    [Parameter] public EventCallback<int> OnSelected { get; set; }

    private async Task HandleClick() => await OnSelected.InvokeAsync(Channel.Id);
}

.channel-item {
    padding: 8px 16px;
    cursor: pointer;
    border-left: 3px solid transparent;
    transition: background-color 0.15s;
}

.channel-item:hover {
    background-color: rgba(255, 255, 255, 0.08);
}

.channel-item.active {
    background-color: rgba(255, 255, 255, 0.12);
    border-left-color: #5865f2;
}

.channel-top-row {
    display: flex;
    align-items: center;
    justify-content: space-between;
}

.channel-name {
    font-weight: 600;
    font-size: 0.95rem;
    color: #dcddde;
}

.channel-item.active .channel-name {
    color: #fff;
}

.unread-badge {
    background-color: #ed4245;
    color: #fff;
    font-size: 0.7rem;
    font-weight: 700;
    padding: 1px 6px;
    border-radius: 10px;
    min-width: 18px;
    text-align: center;
}

.channel-description {
    font-size: 0.78rem;
    color: #8e9297;
    white-space: nowrap;
    overflow: hidden;
    text-overflow: ellipsis;
    margin-top: 2px;
}

@using sv_103e72cc479141729751be7f5a1868a6.Services

<div class="message-item" @onmouseenter="ShowActions" @onmouseleave="HideActions">
    <div class="message-header">
        <span class="message-author">@Message.Author</span>
        <span class="message-time">@FormatRelativeTime(Message.SentAt)</span>
    </div>
    <div class="message-content">@Message.Content</div>

    @if (Message.Reactions.Count > 0)
    {
        <div class="message-reactions">
            @foreach (var reaction in Message.Reactions)
            {
                <button class="reaction-badge" @onclick="() => ReactWith(reaction.Emoji)">
                    @reaction.Emoji @reaction.Users.Count
                </button>
            }
        </div>
    }

    @if (ReplyCount > 0)
    {
        <button class="thread-link" @onclick="HandleOpenThread">
            💬 @ReplyCount @(ReplyCount == 1 ? "reply" : "replies")
        </button>
    }

    @if (_showActions)
    {
        <div class="message-actions">
            @if (ShowReplyAction)
            {
                <button class="action-btn" @onclick="HandleOpenThread" title="Reply in thread">💬</button>
            }
            <button class="action-btn" @onclick="ToggleEmojiPicker" title="Add reaction">😀</button>
        </div>
    }

    @if (_showEmojiPicker)
    {
        <div class="emoji-picker">
            @foreach (var emoji in Emojis)
            {
                <button class="emoji-btn" @onclick="() => ReactWith(emoji)">@emoji</button>
            }
        </div>
    }
</div>

@code {
    private static readonly string[] Emojis = ["👍", "❤️", "😂", "🎉", "🤔", "👀"];

    [Parameter, EditorRequired] public Message Message { get; set; } = default!;
    [Parameter] public int ReplyCount { get; set; }
    [Parameter] public bool ShowReplyAction { get; set; } = true;
    [Parameter] public EventCallback<int> OnOpenThread { get; set; }
    [Parameter] public EventCallback<(int MessageId, string Emoji)> OnReact { get; set; }

    private bool _showActions;
    private bool _showEmojiPicker;

    private void ShowActions() => _showActions = true;

    private void HideActions()
    {
        _showActions = false;
        _showEmojiPicker = false;
    }

    private void ToggleEmojiPicker() => _showEmojiPicker = !_showEmojiPicker;

    private async Task HandleOpenThread() => await OnOpenThread.InvokeAsync(Message.Id);

    private async Task ReactWith(string emoji)
    {
        _showEmojiPicker = false;
        await OnReact.InvokeAsync((Message.Id, emoji));
    }

    private static string FormatRelativeTime(DateTime sentAt)
    {
        var diff = DateTime.UtcNow - sentAt;
        if (diff.TotalSeconds < 30) return "just now";
        if (diff.TotalMinutes < 1) return $"{(int)diff.TotalSeconds}s ago";
        if (diff.TotalMinutes < 60) return $"{(int)diff.TotalMinutes} min ago";
        if (diff.TotalHours < 24) return $"{(int)diff.TotalHours}h ago";
        if (diff.TotalDays < 7) return $"{(int)diff.TotalDays}d ago";
        return sentAt.ToString("MMM d, h:mm tt");
    }
}

