arguments.file_text:
@using sv_103e72cc479141729751be7f5a1868a6.Services

<div class="channel-sidebar">
    <div class="sidebar-header">
        <h3>Channels</h3>
    </div>
    <div class="channel-list">
        @foreach (var channel in Channels)
        {
            <ChannelItem Channel="channel"
                         IsActive="channel.Id == SelectedChannelId"
                         OnSelected="OnChannelSelected" />
        }
    </div>
</div>

@code {
    [Parameter, EditorRequired] public List<Channel> Channels { get; set; } = [];
    [Parameter] public int? SelectedChannelId { get; set; }
    [Parameter] public EventCallback<int> OnChannelSelected { get; set; }
}

.channel-sidebar {
    width: 20%;
    min-width: 220px;
    max-width: 300px;
    background-color: #2f3136;
    color: #dcddde;
    display: flex;
    flex-direction: column;
    border-right: 1px solid #202225;
}

.sidebar-header {
    padding: 16px;
    border-bottom: 1px solid #202225;
}

.sidebar-header h3 {
    margin: 0;
    font-size: 1rem;
    font-weight: 700;
    text-transform: uppercase;
    letter-spacing: 0.04em;
    color: #8e9297;
}

.channel-list {
    flex: 1;
    overflow-y: auto;
    padding: 8px 0;
}

@using sv_103e72cc479141729751be7f5a1868a6.Services

<div class="thread-panel">
    <div class="thread-header">
        <h4>Thread</h4>
        <button class="close-btn" @onclick="OnClose">✕</button>
    </div>

    @if (RootMessage is not null)
    {
        <div class="thread-root">
            <MessageItem Message="RootMessage"
                         ReplyCount="0"
                         ShowReplyAction="false"
                         OnReact="OnReact" />
        </div>

        <div class="thread-divider">
            <span>@Replies.Count @(Replies.Count == 1 ? "reply" : "replies")</span>
        </div>

        <div class="thread-replies">
            @foreach (var reply in Replies)
            {
                <MessageItem Message="reply"
                             ReplyCount="0"
                             ShowReplyAction="false"
                             OnReact="OnReact" />
            }
        </div>

        <MessageInput Placeholder="Reply in thread…" ButtonText="Reply" OnSend="OnReply" />
    }
</div>

@code {
    [Parameter] public Message? RootMessage { get; set; }
    [Parameter] public List<Message> Replies { get; set; } = [];
    [Parameter] public EventCallback OnClose { get; set; }
    [Parameter] public EventCallback<string> OnReply { get; set; }
    [Parameter] public EventCallback<(int MessageId, string Emoji)> OnReact { get; set; }
}

.thread-panel {
    width: 25%;
    min-width: 300px;
    max-width: 420px;
    background-color: #fff;
    border-left: 1px solid #e3e5e8;
    display: flex;
    flex-direction: column;
