@using sv_103e72cc479141729751be7f5a1868a6.Components.Chat
@inject IChatService ChatService
@inject IJSRuntime JS

<div class="chat-container">
    <ChannelSidebar Channels="_channels"
                    SelectedChannelId="_selectedChannelId"
                    OnChannelSelected="SelectChannel" />

    <div class="main-area">
        @if (_selectedChannel is not null)
        {
            <div class="channel-header-bar">
                <div>
                    <h3># @_selectedChannel.Name</h3>
                    <span class="channel-desc">@_selectedChannel.Description</span>
                </div>
            </div>

            <div class="message-list" @ref="_messageListRef">
                @if (_hasMoreMessages)
                {
                    <div class="load-more-wrapper">
                        <button class="load-more-btn" @onclick="LoadOlderMessages" disabled="@_isLoadingMore">
                            @(_isLoadingMore ? "Loading…" : "↑ Load older messages")
                        </button>
                    </div>
                }
                @foreach (var msg in _messages)
                {
                    <MessageItem Message="msg"
                                 ReplyCount="GetReplyCount(msg.Id)"
                                 OnOpenThread="OpenThread"
                                 OnReact="AddReaction" />
                }
            </div>

            <MessageInput Placeholder="@($"Message #{_selectedChannel.Name}")" OnSend="SendMessage" />
        }
        else
        {
            <div class="no-channel">
                <p>Select a channel to start chatting</p>
            </div>
        }
    </div>

    @if (_isThreadOpen)
    {
        <ThreadPanel RootMessage="_threadRootMessage"
                     Replies="_threadReplies"
                     OnClose="CloseThread"
                     OnReply="SendReply"
                     OnReact="AddReaction" />
    }
</div>

@code {
    private List<Channel> _channels = [];
    private int? _selectedChannelId;
    private Channel? _selectedChannel;
    private List<Message> _messages = [];
    private readonly Dictionary<int, int> _replyCounts = new();

    private Message? _threadRootMessage;
    private List<Message> _threadReplies = [];
    private bool _isThreadOpen;

    private bool _hasMoreMessages = true;
    private bool _isLoadingMore;
    private int _skip;
    private const int PageSize = 20;
    private bool _shouldScrollToBottom;

    private ElementReference _messageListRef;
    private IJSObjectReference? _jsModule;

    protected override async Task OnInitializedAsync()
    {
        _channels = await ChatService.GetChannelsAsync();
        if (_channels.Count > 0)
            await SelectChannel(_channels[0].Id);
    }

    protected override async Task OnAfterRenderAsync(bool firstRender)
    {
        if (firstRender)
            _jsModule = await JS.InvokeAsync<IJSObjectReference>("import", "./js/chat.js");

        if (_shouldScrollToBottom && _jsModule is not null)
        {
            _shouldScrollToBottom = false;
            await _jsModule.InvokeVoidAsync("scrollToBottom", _messageListRef);
        }
    }

    private async Task SelectChannel(int channelId)
    {
        _selectedChannelId = channelId;
        _selectedChannel = _channels.FirstOrDefault(c => c.Id == channelId);
        _messages.Clear();
        _replyCounts.Clear();
        _skip = 0;
        _hasMoreMessages = true;
        _isThreadOpen = false;

        await LoadMessages();
        await ChatService.MarkChannelReadAsync(channelId);

        // Clear unread badge locally
        var idx = _channels.FindIndex(c => c.Id == channelId);
        if (idx >= 0)
            _channels[idx] = _channels[idx] with { UnreadCount = 0 };

        _shouldScrollToBottom = true;
    }

    private async Task LoadMessages()
    {
        var batch = await ChatService.GetMessagesAsync(_selectedChannelId!.Value, _skip, PageSize);
        if (batch.Count < PageSize)
            _hasMoreMessages = false;

        _messages.InsertRange(0, batch);
        _skip += batch.Count;

        await LoadThreadSummaries(batch);
    }

    private async Task LoadOlderMessages()
    {
        _isLoadingMore = true;
        await LoadMessages();
        _isLoadingMore = false;
    }

    private async Task LoadThreadSummaries(List<Message> messages)
    {
        foreach (var msg in messages)
        {
            var thread = await ChatService.GetThreadAsync(msg.Id);
            var replyCount = thread.Count - 1; // exclude root
            if (replyCount > 0)
                _replyCounts[msg.Id] = replyCount;
        }
    }

    private int GetReplyCount(int messageId)
        => _replyCounts.GetValueOrDefault(messageId);

    private async Task OpenThread(int messageId)
    {
        _threadRootMessage = _messages.FirstOrDefault(m => m.Id == messageId);
        if (_threadRootMessage is null) return;

        var thread = await ChatService.GetThreadAsync(messageId);
        _threadReplies = thread.Where(m => m.Id != messageId).ToList();
        _isThreadOpen = true;
    }

    private void CloseThread()
    {
        _isThreadOpen = false;
        _threadRootMessage = null;
        _threadReplies.Clear();
    }

    private async Task SendMessage(string content)
    {
        if (_selectedChannelId is null) return;
        var msg = await ChatService.SendMessageAsync(_selectedChannelId.Value, content, null);
        _messages.Add(msg);
        _shouldScrollToBottom = true;
    }

    private async Task SendReply(string content)
    {
        if (_threadRootMessage is null || _selectedChannelId is null) return;
        var reply = await ChatService.SendMessageAsync(_selectedChannelId.Value, content, _threadRootMessage.Id);
        _threadReplies.Add(reply);
        _replyCounts[_threadRootMessage.Id] = _threadReplies.Count;
    }

    private async Task AddReaction((int MessageId, string Emoji) args)
    {
        await ChatService.AddReactionAsync(args.MessageId, args.Emoji);

        var msg = _messages.FirstOrDefault(m => m.Id == args.MessageId)
                  ?? _threadReplies.FirstOrDefault(m => m.Id == args.MessageId);
        if (msg is null) return;

        var existing = msg.Reactions.FirstOrDefault(r => r.Emoji == args.Emoji);
        if (existing is not null)
        {
            if (!existing.Users.Contains("You"))
                existing.Users.Add("You");
        }
        else
        {
            msg.Reactions.Add(new Reaction(args.Emoji, ["You"]));
        }
    }
}

.chat-container {
    display: flex;
    height: 100vh;
    width: 100%;
    overflow: hidden;
    background-color: #fff;
}

.main-area {
    flex: 1;
    display: flex;
    flex-direction: column;
    min-width: 0;
    background-color: #fff;
}

.channel-header-bar {
    display: flex;
    align-items: center;
    padding: 12px 20px;
    border-bottom: 1px solid #e3e5e8;
    background-color: #fff;
    flex-shrink: 0;
}

.channel-header-bar h3 {
    margin: 0;
    font-size: 1.1rem;
    font-weight: 700;
    color: #2e3338;
}

.channel-desc {
    font-size: 0.82rem;
    color: #72767d;
    margin-top: 2px;
    display: block;
}

.message-list {
    flex: 1;
    overflow-y: auto;
    padding: 8px 0;
    display: flex;
    flex-direction: column;
}

.load-more-wrapper {
    display: flex;
    justify-content: center;
    padding: 12px;
}

.load-more-btn {
    padding: 6px 16px;
    background-color: #f2f3f5;
    border: 1px solid #e3e5e8;
    border-radius: 6px;
    color: #5865f2;
    font-size: 0.82rem;
    font-weight: 600;
    cursor: pointer;
    transition: background-color 0.15s;
}

.load-more-btn:hover:not(:disabled) {
    background-color: #e3e5e8;
}

.load-more-btn:disabled {
    opacity: 0.6;
    cursor: not-allowed;
}

.no-channel {
    flex: 1;
    display: flex;
    align-items: center;
    justify-content: center;
    color: #72767d;
    font-size: 1.1rem;
}

