+.chat-container {
+    display: flex;
+    height: 100vh;
+    width: 100%;
+    overflow: hidden;
+    background-color: #fff;
+}
+
+.main-area {
+    flex: 1;
+    display: flex;
+    flex-direction: column;
+    min-width: 0;
+    background-color: #fff;
+}
+
+.channel-header-bar {
+    display: flex;
+    align-items: center;
+    padding: 12px 20px;
+    border-bottom: 1px solid #e3e5e8;
+    background-color: #fff;
+    flex-shrink: 0;
+}
+
+.channel-header-bar h3 {
+    margin: 0;
+    font-size: 1.1rem;
+    font-weight: 700;
+    color: #2e3338;
+}
+
+.channel-desc {
+    font-size: 0.82rem;
+    color: #72767d;
+    margin-top: 2px;
+    display: block;
+}
+
+.message-list {
+    flex: 1;
+    overflow-y: auto;
+    padding: 8px 0;
+    display: flex;
+    flex-direction: column;
+}
+
+.load-more-wrapper {
+    display: flex;
+    justify-content: center;
+    padding: 12px;
+}
+
+.load-more-btn {
+    padding: 6px 16px;
+    background-color: #f2f3f5;
+    border: 1px solid #e3e5e8;
+    border-radius: 6px;
+    color: #5865f2;
+    font-size: 0.82rem;
+    font-weight: 600;
+    cursor: pointer;
+    transition: background-color 0.15s;
+}
+
+.load-more-btn:hover:not(:disabled) {
+    background-color: #e3e5e8;
+}
+
+.load-more-btn:disabled {
+    opacity: 0.6;
+    cursor: not-allowed;
+}
+
+.no-channel {
+    flex: 1;
+    display: flex;
+    align-items: center;
+    justify-content: center;
+    color: #72767d;
+    font-size: 1.1rem;
+}
